+            min_y = min_y.min(y);
+            max_y = max_y.max(y);
+        }
+
+        for y in min_y..=max_y {
+            for x in min_x..=max_x {
+                if point_in_convex_polygon(x, y, points) {
+                    self.point(x, y);
+                }
+            }
